Code.Terraform:
```hcl
# 启用 Security Hub
resource "aws_securityhub_account" "<example_resource_name>" {}

# 关键：至少启用一项标准，以便检查通过
resource "aws_securityhub_standards_subscription" "<example_resource_name>_fsbp" {
  standards_arn = "arn:aws:securityhub:<REGION>::standards/aws-foundational-security-best-practices/v/1.0.0" # 启用 AWS FSBP
}
```
